// Data layer for the model-centric views (homepage models section,
// /models/[slug], per-bench model lists). Types, constants, and pure
// transforms over public/data/models.json (regenerated by
// scripts/build_model_index.py on every publish). This module is
// client-component-safe: the fs reader lives in ./models.server.

export type Bench = "hard" | "mega" | "cuda"

export interface ModelCell {
  run_id: string | null
  correct: boolean
  score: number | null
  verdict: string
  valid: boolean
  elapsed_seconds?: number | null
  tok_s?: number | null
  ctx?: Record<string, number>
  framework?: string | null
  solution_url: string | null
  trace_url: string | null
}

export interface FlagEntry {
  run_id: string
  verdict: string
  summary: string
}

export interface GpuBlock {
  label: string | null
  harness: string | null
  effort: string | null
  passed: number
  total_problems: number
  perf: number | null
  cells: Record<string, ModelCell>
}

export interface BenchBlock extends GpuBlock {
  audited: number
  flagged: number
  flags: FlagEntry[]
  gpus: Record<string, GpuBlock>
}

export interface LegacyBlock {
  best_pass_count: number
  total_problems: number
  labels: string[]
}

export interface ModelEntry {
  slug: string
  name: string
  lab: string
  benches: Partial<Record<Bench, BenchBlock>>
  legacy: Record<string, LegacyBlock>
  totals: { audited: number; flagged: number }
}

export interface ModelIndex {
  generated: string
  benches: Record<
    string,
    {
      problems: string[]
      gpu: string
      gpus?: string[]
      gpu_labels?: Record<string, string>
    }
  >
  methodology: string
  models: ModelEntry[]
}

export const BENCH_LABELS: Record<Bench, string> = {
  hard: "Hard",
  mega: "Mega",
  cuda: "CUDA",
}

export const PROBLEM_LABELS: Record<string, string> = {
  "01_fp8_gemm": "FP8 GEMM",
  "02_kda_cutlass": "KDA CUTLASS",
  "03_paged_attention": "Paged Attention",
  "05_topk_bitonic": "TopK Bitonic",
  "06_sonic_moe_swiglu": "Sonic MoE",
  "07_w4a16_gemm": "W4A16 GEMM",
  "01_rl_grid_ppo": "RL Grid PPO",
  "02_kimi_linear_decode": "Kimi-Linear Decode",
  "01_glm52_fused_moe": "GLM-5.2 Fused MoE",
  "02_deepseek_nsa": "DeepSeek NSA",
  "03_megaqwen_decode": "MegaQwen Decode",
  "04_grid_mingru_sps": "Grid + MinGRU SPS",
  "01_rmsnorm_residual": "RMSNorm + Residual",
  "02_online_softmax": "Online Softmax",
}

export const FLAG_VERDICTS = new Set([
  "reward_hack",
  "contamination",
  "rubric_leak",
  "megakernel_not_authentic",
])

/**
 * Lab brand presentation for charts (AA-style: bar color + logo keyed by lab).
 * Logos are white-fill SVGs vendored from simple-icons into public/logos/labs.
 * Labs without a vendored mark render a letter chip instead.
 */
export interface Brand {
  color: string
  logo: string | null
}

export const LAB_BRANDS: Record<string, Brand> = {
  Anthropic: { color: "#d97757", logo: "/logos/labs/anthropic.svg" },
  OpenAI: { color: "#19c37d", logo: null },
  Google: { color: "#5e97f6", logo: "/logos/labs/google.svg" },
  xAI: { color: "#e6e6e6", logo: null },
  DeepSeek: { color: "#5b7cfa", logo: "/logos/labs/deepseek.svg" },
  "Moonshot AI": { color: "#8b7cf6", logo: null },
  "Z.ai": { color: "#38b6ff", logo: null },
  MiniMax: { color: "#f87171", logo: "/logos/labs/minimax.svg" },
  Meituan: { color: "#ffd60a", logo: "/logos/labs/meituan.svg" },
  NVIDIA: { color: "#76b900", logo: "/logos/labs/nvidia.svg" },
  Alibaba: { color: "#a78bfa", logo: "/logos/labs/alibabacloud.svg" },
  Cursor: { color: "#c9c9c9", logo: "/logos/labs/cursor.svg" },
  Xiaomi: { color: "#ff7a1a", logo: "/logos/labs/xiaomi.svg" },
  Meta: { color: "#0082fb", logo: "/logos/labs/meta.svg" },
  "Sakana AI": { color: "#f472b6", logo: null },
}

export function brandFor(lab: string, slug: string): Brand {
  const hit = LAB_BRANDS[lab]
  if (hit) return hit
  // deterministic fallback hue from the slug
  let h = 0
  for (let i = 0; i < slug.length; i++) h = (h * 31 + slug.charCodeAt(i)) % 360
  return { color: `hsl(${h} 55% 62%)`, logo: null }
}

export function problemLabel(key: string): string {
  return PROBLEM_LABELS[key] ?? key.replace(/^\d+_/, "").replace(/_/g, " ")
}

export function benchValue(bench: Bench, score: number): string {
  return bench === "mega" ? `${score.toFixed(2)}x` : `${(score * 100).toFixed(1)}%`
}

export function auditChipClass(verdict: string): string {
  if (FLAG_VERDICTS.has(verdict)) return "audit-chip audit-chip-bad"
  if (verdict === "clean") return "audit-chip audit-chip-clean"
  if (verdict === "unaudited") return "audit-chip audit-chip-muted"
  return "audit-chip audit-chip-warn"
}

// ---- Ranked model-list views ------------------------------------------------

export interface ModelRow {
  slug: string
  name: string
  lab: string
  subtitle: string
  passed: number
  total: number
  perf: number | null
  audited: number
  flagged: number
  badges: { label: string; value: string; tone: "good" | "muted" }[]
  /** benches fully passed (index view); ignored by per-bench views */
  full: number
}

function harnessSubtitle(block: GpuBlock | null | undefined): string {
  if (!block) return ""
  return [block.harness, block.effort].filter(Boolean).join(" · ")
}

/** One row per model with a canonical board presence, ranked
 *  pass-rate desc -> passed desc -> perf desc (nulls last) -> slug. */
export function rowsForBench(
  index: ModelIndex,
  bench: Bench,
  gpu?: string,
): { board: ModelRow[]; sink: ModelRow[] } {
  const board: ModelRow[] = []
  const sink: ModelRow[] = []
  const gpuLabels = index.benches[bench]?.gpu_labels ?? {}
  for (const m of index.models) {
    const block = m.benches[bench]
    if (!block) continue
    const view: GpuBlock | undefined = gpu ? block.gpus?.[gpu] : block
    const onBoard = !!view && (view.passed > 0 || Object.keys(view.cells).length > 0)
    if (onBoard && view) {
      board.push({
        slug: m.slug,
        name: m.name,
        lab: m.lab,
        subtitle: harnessSubtitle(view),
        passed: view.passed,
        total: view.total_problems,
        perf: view.perf,
        audited: block.audited ?? 0,
        flagged: block.flagged ?? 0,
        badges: [],
        full: 0,
      })
      continue
    }
    // Sink view only exists on the canonical board (audits are bench-level,
    // not split per GPU).
    if (gpu) continue
    if ((block.audited ?? 0) === 0 && (block.flagged ?? 0) === 0) continue
    const gpuNotes = Object.entries(block.gpus ?? {})
      .filter(([, g]) => g.passed > 0)
      .map(([k, g]) => `${gpuLabels[k] ?? k}: ${g.passed}/${g.total_problems}`)
    sink.push({
      slug: m.slug,
      name: m.name,
      lab: m.lab,
      subtitle: gpuNotes.length ? `other boards: ${gpuNotes.join(" · ")}` : "",
      passed: 0,
      total: block.total_problems,
      perf: null,
      audited: block.audited ?? 0,
      flagged: block.flagged ?? 0,
      badges: [],
      full: 0,
    })
  }
  board.sort(compareRows)
  sink.sort((a, b) => a.slug.localeCompare(b.slug))
  return { board, sink }
}

export function compareRows(a: ModelRow, b: ModelRow): number {  const ar = a.total > 0 ? a.passed / a.total : 0
  const br = b.total > 0 ? b.passed / b.total : 0
  if (br !== ar) return br - ar
  if (b.passed !== a.passed) return b.passed - a.passed
  const ap = a.perf ?? -1
  const bp = b.perf ?? -1
  if (bp !== ap) return bp - ap
  return a.slug.localeCompare(b.slug)
}

/** Homepage index view: rank by benches fully passed, then mean normalized
 *  perf across benches attempted; per-bench pass chips on every row. */
export function rowsForIndex(index: ModelIndex): { board: ModelRow[]; sink: ModelRow[] } {
  const benches: Bench[] = ["mega", "hard", "cuda"]
  const board: ModelRow[] = []
  const sink: ModelRow[] = []
  for (const m of index.models) {
    const attempted = benches.filter((b) => {
      const blk = m.benches[b]
      return blk && (blk.passed > 0 || Object.keys(blk.cells).length > 0)
    })
    if (attempted.length === 0) {
      if (m.totals.audited > 0 || m.totals.flagged > 0) {
        sink.push({ ...makeIndexRow(m, [], null), full: 0 })
      }
      continue
    }
    const full = attempted.filter((b) => {
      const blk = m.benches[b]!
      return blk.total_problems > 0 && blk.passed >= blk.total_problems
    }).length
    const perfs = attempted
      .map((b) => m.benches[b]!.perf)
      .filter((p): p is number => p != null)
    const meanPerf = perfs.length ? perfs.reduce((s, p) => s + p, 0) / perfs.length : null
    board.push({ ...makeIndexRow(m, attempted as Bench[], meanPerf), full })
  }
  board.sort((a, b) => {
    if (b.full !== a.full) return b.full - a.full
    const ap = a.perf ?? -1
    const bp = b.perf ?? -1
    if (bp !== ap) return bp - ap
    return a.slug.localeCompare(b.slug)
  })
  sink.sort((a, b) => a.slug.localeCompare(b.slug))
  return { board, sink }
}

function makeIndexRow(
  m: ModelEntry,
  attempted: Bench[],
  meanPerf: number | null,
): Omit<ModelRow, "full"> {
  const order: Bench[] = ["mega", "hard", "cuda"]
  const badges = order
    .filter((b) => attempted.includes(b))
    .map((b) => {
      const blk = m.benches[b]!
      const full = blk.total_problems > 0 && blk.passed >= blk.total_problems
      return {
        label: BENCH_LABELS[b].toUpperCase(),
        value: `${blk.passed}/${blk.total_problems}`,
        tone: full ? ("good" as const) : ("muted" as const),
      }
    })
  const totalPassed = attempted.reduce((s, b) => s + m.benches[b]!.passed, 0)
  const totalProblems = attempted.reduce((s, b) => s + m.benches[b]!.total_problems, 0)
  return {
    slug: m.slug,
    name: m.name,
    lab: m.lab,
    subtitle: "",
    passed: totalPassed,
    total: totalProblems,
    perf: meanPerf,
    audited: m.totals.audited,
    flagged: m.totals.flagged,
    badges,
  }
}

// ---- AA-style bar-chart views ------------------------------------------------

export interface BarRow {
  slug: string
  name: string
  lab: string
  subtitle: string
  passed: number
  total: number
  /** bench-native display metric: mean peak fraction (hard/cuda) or best
   *  speedup over baseline (mega) across valid cells */
  value: number
  display: string
  flagged: number
  audited: number
  brand: Brand
}

export interface BarView {
  bench: Bench
  axis: string
  rows: BarRow[]
  maxValue: number
}

/** AA-style horizontal bar chart data for one bench (optionally one GPU
 *  board): one bar per model, ordered by the same rank rule as the lists
 *  (valid passes desc, then normalized perf desc). */
export function barsForBench(
  index: ModelIndex,
  bench: Bench,
  gpu?: string,
): BarView {
  const { board } = rowsForBench(index, bench, gpu)
  const rows: BarRow[] = []
  for (const row of board) {
    const model = index.models.find((m) => m.slug === row.slug)!
    const block = model.benches[bench]!
    const view: GpuBlock = gpu ? block.gpus[gpu]! : block
    const vals = Object.values(view.cells).filter((c) => c.valid && c.score != null)
    let value = 0
    if (vals.length > 0) {
      if (bench === "mega") {
        value = Math.max(...vals.map((c) => c.score!))
      } else {
        value = vals.reduce((s, c) => s + c.score!, 0) / vals.length
      }
    }
    rows.push({
      slug: row.slug,
      name: model.name,
      lab: row.lab,
      subtitle: row.subtitle,
      passed: row.passed,
      total: row.total,
      value,
      display: bench === "mega" ? `${value.toFixed(2)}x` : `${(value * 100).toFixed(1)}%`,
      flagged: row.flagged,
      audited: row.audited,
      brand: brandFor(row.lab, row.slug),
    })
  }
  const maxValue = Math.max(0, ...rows.map((r) => r.value))
  const axis =
    bench === "mega"
      ? "best decode speedup vs optimized-PyTorch baseline (valid cells)"
      : "mean peak fraction of roofline (valid cells)"
  return { bench, axis, rows, maxValue }
}

// ---- AA-style vertical column charts ---------------------------------------
//
// Scoring conventions (KEEP SIMPLE AND AUDITABLE — every number below is
// plain arithmetic over public/data/models.json; a fresh agent conversation
// should be able to recompute any chart value by hand):
//
// 1) HARD / CUDA performance chart, one column per model:
//      score_m = mean(peak_fraction) over the model's VALID cells on the
//                bench's canonical board (valid = correct AND audited-clean;
//                problems with no valid cell are EXCLUDED from the mean).
//    Worked example (real data): glm-5.2 has 6/6 valid hard cells whose mean
//    peak fraction is 0.2614 -> bar renders 26.1% of roofline.
//    Why no per-problem weighting: a raw mean under-weights launch-bound
//    problems, it can never be swayed by them — topk's ~0.02 ceiling adds at
//    most 0.02/6 = 0.3 points to a 6-problem mean, while fp8/KDA (~0.3-0.5)
//    dominate. That is the same convention the published leaderboard uses.
//
// 2) MEGA performance chart:
//      score_m = max(speedup) over the model's valid cells on the canonical
//                board. Each cell's score is already the run's geomean
//                decode speedup vs the optimized-PyTorch baseline across
//                contexts; the model's best published cell wins.
//    Worked example (real data): claude-fable-5's best valid mega cell is
//    18.715 -> bar renders 18.7x.
//
// 3) CORRECTNESS chart (single "compiled" chart below the perf charts):
//      pct_m = 100 * passed / total, summed over the CANONICAL boards of
//              every bench the model has any published cells on (a bench the
//              model never attempted does not enter the denominator).
//    Worked example (real data): grok-4.5 is 6/6 hard + 1/2 mega + 4/4 cuda
//    = 11/12 = 91.67% -> bar label rounds to "92%". A model that attempted a
//    bench and solved nothing renders a real 0% label; a model with no cells
//    anywhere renders no bar.
//
// 4) Column ORDER is shared across all four charts (correctness % desc ->
//    total passed desc -> slug) so a model sits in the same slot on every
//    panel; charts disagree only in bar height, like AA's index views.
//
// 5) A model with no valid cell on a chart keeps its column slot but renders
//    no bar (per product decision 2026-07-16: "just don't render the bar,
//    we'll fill that percentage in automatically" as new results land).

export interface ColPoint {
  slug: string
  name: string
  lab: string
  /** bar value in bench-native units (fraction 0..1, speedup, or 0..100 pct);
   *  null = no result yet -> no bar rendered */
  value: number | null
  /** top-of-bar label, e.g. "26.1%" / "18.72x"; null when value is null */
  display: string | null
  brand: Brand
}

export interface ColChart {
  title: string
  /** formula in words, rendered under the title so the math is on-page */
  subtitle: string
  /** y-axis unit: "%" renders labels as percents of a fraction axis (0..1
   *  data), "x" as raw multipliers, "pct" as 0..100 percents */
  unit: "%" | "x" | "pct"
  columns: ColPoint[]
  /** y-axis top (data units); 100 for the pct chart */
  maxValue: number
}

/** Per-model correctness across canonical boards: { pct, passed, total }. */
function correctnessOf(index: ModelIndex, m: ModelEntry): {
  pct: number | null
  passed: number
  total: number
} {
  const order: Bench[] = ["mega", "hard", "cuda"]
  let passed = 0
  let total = 0
  for (const b of order) {
    const blk = m.benches[b]
    if (!blk) continue
    const attempted = Object.keys(blk.cells).length > 0
    if (!attempted && blk.total_problems === 0) continue
    passed += blk.passed
    total += blk.total_problems
  }
  if (total === 0) return { pct: null, passed, total }
  return { pct: (100 * passed) / total, passed, total }
}

/**
 * Canonical column order, shared by every chart: correctness % desc ->
 * total passed desc -> slug. Models with no attempted bench (pct null) sink
 * to the right, ordered by slug.
 */
export function columnOrder(index: ModelIndex): ModelEntry[] {
  return [...index.models].sort((am, bm) => {
    const a = correctnessOf(index, am)
    const b = correctnessOf(index, bm)
    const ap = a.pct ?? -1
    const bp = b.pct ?? -1
    if (bp !== ap) return bp - ap
    if (b.passed !== a.passed) return b.passed - a.passed
    return am.slug.localeCompare(bm.slug)
  })
}

/**
 * Round the data max up to a "nice" axis top: smallest 4-step grid that
 * covers `v`. Step ladder doubles as the gridline spacing.
 * Examples: hard max 0.2614 -> 0.4 (lines at .1/.2/.3/.4);
 *           mega max 18.715  -> 20  (lines at 5/10/15/20).
 */
export function niceCeil(v: number): number {
  const steps = [0.02, 0.05, 0.1, 0.2, 0.25, 0.5, 1, 2, 2.5, 5, 10, 20, 25, 50, 100]
  for (const s of steps) if (4 * s >= v) return 4 * s
  return Math.ceil(v)
}

/** Vertical-column data for one bench's canonical board. Every model keeps a
 *  slot; models with no valid cell on the bench get value/display = null. */
export function columnsForBench(
  index: ModelIndex,
  bench: Bench,
  ordered?: ModelEntry[],
): ColChart {
  const models = ordered ?? columnOrder(index)
  const columns: ColPoint[] = []
  let maxValue = 0
  for (const m of models) {
    let value: number | null = null
    const block = m.benches[bench]
    if (block) {
      const vals = Object.values(block.cells).filter(
        (c) => c.valid && c.score != null,
      )
      if (vals.length > 0) {
        value =
          bench === "mega"
            ? Math.max(...vals.map((c) => c.score!))
            : vals.reduce((s, c) => s + c.score!, 0) / vals.length
      }
    }
    if (value != null && value > maxValue) maxValue = value
    columns.push({
      slug: m.slug,
      name: m.name,
      lab: m.lab,
      value,
      display:
        value == null
          ? null
          : bench === "mega"
            ? `${value.toFixed(2)}x`
            : `${(value * 100).toFixed(1)}%`,
      brand: brandFor(m.lab, m.slug),
    })
  }
  const label = BENCH_LABELS[bench]
  const gpuRaw = index.benches[bench]?.gpu
  const gpu =
    typeof gpuRaw === "string" ? gpuRaw : (gpuRaw as { name?: string } | undefined)?.name ?? "RTX PRO 6000"
  return {
    title: `${label} performance`,
    subtitle:
      bench === "mega"
        ? `best decode speedup vs optimized-PyTorch baseline over valid (correct + audited-clean) cells · ${gpu}`
        : `mean peak fraction of roofline over valid (correct + audited-clean) cells · ${gpu}`,
    unit: bench === "mega" ? "x" : "%",
    columns,
    maxValue: niceCeil(maxValue),
  }
}

/** The single "compiled" correctness chart: % of published problems each
 *  model gets correct, summed over canonical boards of attempted benches. */
export function columnsForCorrectness(index: ModelIndex, ordered?: ModelEntry[]): ColChart {
  const models = ordered ?? columnOrder(index)
  const columns: ColPoint[] = models.map((m) => {
    const { pct } = correctnessOf(index, m)
    return {
      slug: m.slug,
      name: m.name,
      lab: m.lab,
      value: pct,
      display: pct == null ? null : `${pct.toFixed(0)}%`,
      brand: brandFor(m.lab, m.slug),
    }
  })
  return {
    title: "Correctness",
    subtitle:
      "published problems correct, summed over attempted benches (passed / total on canonical boards)",
    unit: "pct",
    columns,
    maxValue: 100,
  }
}
